@PostMapping("/users")
public ResponseEntity<User> createUser(@RequestBody @Valid UserDto dto) {
  User user = new User();
  user.setEmail(dto.getEmail()); // @Email constraint on field
  user.setAge(dto.getAge());     // @Min(0) @Max(150) on field
  return ResponseEntity.ok(userRepo.save(user));
}

